const NotificationBadge={STORAGE_KEY: 'sadec-notification-count',container: null,init(){this.findOrCreateContainer();this.render();this.loadFromStorage();this.bindRefresh();},findOrCreateContainer(){this.container=document.querySelector('[data-notification-badge]');if(!this.container){this.container=document.createElement('span');this.container.setAttribute('data-notification-badge','');this.container.className='notification-badge';const profileIcon=document.querySelector('.profile-icon,.user-menu,[data-user]');if(profileIcon){profileIcon.style.position='relative';this.container.style.position='absolute';this.container.style.top='-8px';this.container.style.right='-8px';profileIcon.appendChild(this.container);}else{const header=document.querySelector('header,.header,.top-nav');if(header){header.appendChild(this.container);}}}},render(){const count=parseInt(localStorage.getItem(this.STORAGE_KEY)||'0',10);if(count<=0){this.container.style.display='none';}else if(count>99){this.container.textContent='99+';this.container.style.display='inline-flex';}else{this.container.textContent=count;this.container.style.display='inline-flex';}},loadFromStorage(){this.render();},setCount(count){localStorage.setItem(this.STORAGE_KEY,count.toString());this.render();this.dispatchUpdate(count);},increment(delta=1){const current=parseInt(localStorage.getItem(this.STORAGE_KEY)||'0',10);this.setCount(current+delta);},decrement(delta=1){const current=parseInt(localStorage.getItem(this.STORAGE_KEY)||'0',10);this.setCount(Math.max(0,current-delta));},clear(){this.setCount(0);},bindRefresh(){window.addEventListener('notification-refresh',(e)=>{if(e.detail&&typeof e.detail.count==='number'){this.setCount(e.detail.count);}});if(this.container.hasAttribute('data-poll-interval')){const interval=parseInt(this.container.getAttribute('data-poll-interval'),10)||30000;setInterval(()=>this.fetchCount(),interval);}},async fetchCount(){},dispatchUpdate(count){window.dispatchEvent(new CustomEvent('notification-badge-update',{detail:{count}}));}};if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>NotificationBadge.init());}else{NotificationBadge.init();}